package com.careeros.resume.application;
import com.careeros.ai.application.AIProvider;import com.careeros.common.exception.*;import com.careeros.documents.application.*;import com.careeros.documents.infrastructure.ResumeDocumentProperties;import com.careeros.job.domain.*;import com.careeros.prompt.application.PromptTemplateService;import com.careeros.resume.domain.*;import com.careeros.validation.application.ResumeGroundingValidator;import com.fasterxml.jackson.databind.ObjectMapper;import org.springframework.data.domain.*;import org.springframework.stereotype.Service;import java.nio.file.*;import java.time.*;import java.util.*;
@Service public class ResumeTailoringService{private final ResumeVersionRepository versions;private final JobPostingRepository jobs;private final AIProvider ai;private final ResumeDocumentPort documents;private final PdfConverter pdf;private final ResumeDocumentProperties config;private final ResumeArtifactPathFactory artifactPaths;private final PromptTemplateService prompts;private final ResumeGroundingValidator validator;private final ObjectMapper json;public ResumeTailoringService(ResumeVersionRepository v,JobPostingRepository j,AIProvider a,ResumeDocumentPort d,PdfConverter p,ResumeDocumentProperties c,ResumeArtifactPathFactory f,PromptTemplateService t,ResumeGroundingValidator g,ObjectMapper o){versions=v;jobs=j;ai=a;documents=d;pdf=p;config=c;artifactPaths=f;prompts=t;validator=g;json=o;}
 public ResumeVersion generate(Command c){JobPosting job=jobs.findById(c.jobId()).orElseThrow(()->ResourceNotFoundException.forId("JobPosting",c.jobId()));String model=c.model()==null||c.model().isBlank()?"llama3.1:8b":c.model();ResumeVersion version=versions.save(ResumeVersion.generating(versions.nextVersion(),job,c.applicationId(),model,PromptTemplateService.VERSION));Instant start=Instant.now();try{Path master=Path.of(require(config.masterPath(),"MASTER_RESUME_PATH is not configured"));var extracted=documents.extract(master);String prompt=prompts.render(Map.of("master_resume",extracted.text(),"job_title",job.getTitle(),"job_description",Objects.toString(job.getDescription(),""),"match_explanation",Objects.toString(c.matchExplanation(),""),"notes",Objects.toString(c.notes(),""),"skills",String.join(", ",safe(c.skills())),"soft_skills",String.join(", ",safe(c.softSkills()))));var generated=ai.generateJson(model,prompt);var validation=validator.validate(extracted.text(),generated.bullets());if(!validation.valid()){generated=ai.generateJson(model,prompt+"\nVALIDATION FAILURE: "+String.join("; ",validation.warnings())+". Retry once and use only exact facts from MASTER RESUME.");validation=validator.validate(extracted.text(),generated.bullets());}List<String>bullets=validation.valid()?generated.bullets():extracted.bullets();List<String>warnings=new ArrayList<>(generated.warnings());warnings.addAll(validation.warnings());if(!validation.valid())warnings.add("Conservative fallback used original master-resume bullets");var paths=artifactPaths.create(Path.of(config.outputDirectory()).toAbsolutePath(),job.getCompany().getName(),LocalDate.now(),job.getId(),version.getVersionNumber(),config.artifactBaseName());Path docx=documents.generate(master,paths.docx(),bullets);Path pdfPath=null;try{pdfPath=pdf.convert(docx,paths.docx().getParent());}catch(Exception e){warnings.add("PDF generation failed: "+e.getMessage());}version.complete(Duration.between(start,Instant.now()).toMillis(),validation.valid()?"VALID":"CONSERVATIVE_FALLBACK",join(warnings),write(bullets),docx.toString(),pdfPath==null?null:pdfPath.toString());ResumeVersion saved=versions.save(version);return versions.findById(saved.getId()).orElseThrow();}catch(Exception e){version.fail(Duration.between(start,Instant.now()).toMillis(),e.getMessage());versions.save(version);throw e;}}
 public Page<ResumeVersion>list(Pageable p){return versions.findAll(p);}public List<ResumeVersion>history(UUID job){return versions.findByJobId(job);}public ResumeVersion get(UUID id){return versions.findById(id).orElseThrow(()->ResourceNotFoundException.forId("ResumeVersion",id));}public void archive(UUID id){var v=get(id);v.archive();versions.save(v);}public ResumeVersion restore(UUID id){var v=get(id);v.restore();versions.save(v);return get(id);}public Path artifact(UUID id,String format){var v=get(id);String value=format.equalsIgnoreCase("pdf")?v.getPdfPath():v.getDocxPath();if(value==null)throw new IllegalStateException(format.toUpperCase()+" artifact is unavailable");Path path=Path.of(value);if(!Files.isRegularFile(path))throw new IllegalStateException("Resume artifact is missing: "+path);v.downloaded();versions.save(v);return path;}public Health health(){return new Health(ai.name(),ai.healthy(),ai.models(),"Resume processing stays on this machine");}private String write(Object o){try{return json.writeValueAsString(o);}catch(Exception e){throw new IllegalStateException(e);}}private String join(List<String>x){return String.join("\n",x);}private String require(String x,String m){if(x==null||x.isBlank())throw new IllegalStateException(m);return x;}private<T>List<T>safe(List<T>x){return x==null?List.of():x;}public record Command(UUID jobId,UUID applicationId,String model,String notes,List<String>skills,List<String>softSkills,String matchExplanation){}public record Health(String provider,boolean healthy,List<String>models,String privacy){}
}
